window.ASBAB_NUZUL_CACHE["22"] = {"asbab_nuzul":{"19":[{"ar":"عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رضي الله عنه أَنَّهُ قَالَ: أَنَا أَوَّلُ مَنْ يَجْثُو بَيْنَ يَدَيِ الرَّحْمَـٰنِ لِلْخُصُومَةِ يَوْمَ الْقِيَامَةِ، وَقَالَ قَيْسُ بْنُ عُبَادٍ: وَفِيهِمْ أُنْزِلَتْ: { هَـٰذَانِ خَصْمَانِ ٱخْتَصَمُوا۟ فِى رَبِّهِمْ ۖ }، قَالَ: هُمُ الَّذِينَ تَبَارَزُوا يَوْمَ بَدْرٍ: حَمْزَةُ وَعَلِيٌّ وَعُبَيْدَةُ، أَوْ أبو عُبَيْدَةَ بْنُ الْحَارِثِ، وَشَيْبَةُ بْنُ رَبِيعَةَ وَعُتْبَةُ بْنُ رَبِيعَةَ وَالوَلِيدُ بْنُ عُتْبَةَ. واللفظ للبخاري. \n\nوجاء عَنْ أَبِي ذَرٍّ رضي الله عنه شبيهاً من الحديث السابق.","id":""}],"39":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: لَمَّا أُخْرِجَ النَّبِيُّ ﷺ مِنْ مَكَّةَ، قَالَ أَبُو بَكْرٍ: أَخْرَجُوا نَبِيَّهُمْ، إِنَّا لله وَإِنَّا إِلَيْهِ رَاجِعُونَ، لَيَهْلِكُنَّ، فَنَزَلَتْ: { أُذِنَ لِلَّذِينَ يُقَـٰتَلُونَ بِأَنَّهُمْ ظُلِمُوا۟ ۚ وَإِنَّ ٱللَّهَ عَلَىٰ نَصْرِهِمْ لَقَدِيرٌ ﴿٣٩﴾ }، قَالَ: فَعُرِفَ أَنَّهُ سَيَكُونُ قِتَالٌ، قَالَ ابْنُ عَبَّاسٍ، هِيَ أَوَّلُ آيَة نَزَلَتْ فِي الْقِتَالِ. واللفظ للترمذي.","id":""}]},"mapping_ayat":{"22:1":[{"p":"Tirmidzi","n":2796,"ar":"حَدَّثَنَا أَبُو زُرْعَةَ وَالْفَضْلُ بْنُ أَبِي طَالِبٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا الْحَسَنُ بْنُ بِشْرٍ عَنْ الْحَكَمِ بْنِ عَبْدِ الْمَلِكِ عَنْ قَتَادَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَلَا نَعْرِفُ لِقَتَادَةَ سَمَاعًا مِنْ أَحَدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ أَنَسٍ وَأَبِي الطُّفَيْلِ وَهَذَا عِنْدِي مُخْتَصَرٌ إِنَّمَا يُرْوَى عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَرَأَ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ }الْحَدِيثَ بِطُولِهِ وَحَدِيثُ الْحَكَمِ بْنِ عَبْدِ الْمَلِكِ عِنْدِي مُخْتَصَرٌ مِنْ هَذَا الْحَدِيثِ","trj":"Telah menceritakan kepada kami [Abu Zur'ah] dan [Al Fadhal bin Abu Thalib] dan yang lainnya, mereka berkata; telah menceritakan kepada kami [Al Hasan bin Bisyr] dari [Al Hakam bin Abdul Malik] dari [Qatadah] dari ['Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam membaca: \"WATARAN NAASA SUKAARAA WA MAA HUM BI SUKAARAA (kamu lihat manusia dalam keadaan mabuk, padahal Sebenarnya mereka tidak mabuk).\" QS Al-Hajj: 2. Abu Isa berkata; Hadits ini hasan, kami tidak mengetahui Qatadah pernah mendengar dari salah seorang sahabat Nabi shallallahu 'alaihi wasallam kecuali dari Anas dan Abu Thufail, dan hadits ini menurut saya hanya ringkasan, hadits ini hanya diriwayatkan dari [Qatadah] dari [Al Hasan] dari [Imran bin Hushain], dia berkata; Kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, kemudian beliau membaca: \"YAA AYYUHAN NAASUT TAQUU RABBAKUM (Wahai sekalian manusia, takutlah kalian kepada Rabb kalian).\" QS Al Hajj: 1 dengan redaksi yang panjang, sementara hadits Al Hakam bin Abdul Malik menurutku ringkasan dari hadits ini."}],"22:2":[{"p":"Bukhari","n":3053,"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْأَعْمَشِ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ تَعَالَى يَا آدَمُ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ فَيَقُولُ أَخْرِجْ بَعْثَ النَّارِ قَالَ وَمَا بَعْثُ النَّارِ قَالَ مِنْ كُلِّ أَلْفٍ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ فَعِنْدَهُ يَشِيبُ الصَّغِيرُ{ وَتَضَعُ كُلُّ ذَاتِ حَمْلٍ حَمْلَهَا وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى وَلَكِنَّ عَذَابَ اللَّهِ شَدِيدٌ }قَالُوا يَا رَسُولَ اللَّهِ وَأَيُّنَا ذَلِكَ الْوَاحِدُ قَالَ أَبْشِرُوا فَإِنَّ مِنْكُمْ رَجُلًا وَمِنْ يَأْجُوجَ وَمَأْجُوجَ أَلْفًا ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي أَرْجُو أَنْ تَكُونُوا رُبُعَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَا فَقَالَ أَرْجُو أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَا فَقَالَ أَرْجُو أَنْ تَكُونُوا نِصْفَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَا فَقَالَ مَا أَنْتُمْ فِي النَّاسِ إِلَّا كَالشَّعَرَةِ السَّوْدَاءِ فِي جِلْدِ ثَوْرٍ أَبْيَضَ أَوْ كَشَعَرَةٍ بَيْضَاءَ فِي جِلْدِ ثَوْرٍ أَسْوَدَ","trj":"Telah bercerita kepadaku [Ishaq bin Nashr] telah bercerita kepada kami [Abu Usamah] dari [Al A'masy] telah bercerita kepada kami [Abu Shalih] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: \"Wahai Adam, \". Nabi Adam 'Alaihissalam menjawab: \"Labbaika, kemuliaan milik-Mu dan segala kebaikan berada di tangan-Mu\". Kemudian Allah berfirman: \"Keluarkanlah utusan neraka\". Adam bertanya; \"Apa yang dimaksud dengan utusan neraka? (berapa jumlahnya?) \". Allah berfirman: \"Dari setiap seribu, sembilan ratus sembilan puluh Sembilan dijebloskan neraka!, Ketika perintah ini diputuskan, maka anak-anak belia menjadi beruban, dan setiap wanita hamil kandungannya berguguran dan kamu lihat manusia mabuk padahal mereka tidaklah mabuk akan tetapi (mereka melihat) siksa Allah yang sangat keras\". (QS. Alhajj 2), Para shahabat bertanya; \"Wahai Rasulullah, adakah diantara kami seseorang yang selamat?\". Beliau bersabda: \"Bergembiralah, karena setiap seribu yang dimasukkan neraka, dari kalian cuma satu, sedang Sembilan ratus sembilan puluh sembilannya dari Ya'juj dan ma'juj\". Kemudian Beliau bersabda: \"Dan demi Dzat yang jiwaku berada di tangan-Nya, aku berharap kalian menjadi di antara seperempat ahlu surga\". Maka kami bertakbir. Kemudian Beliau bersabda lagi: \"Aku berharap kalian menjadi di antara sepertiga ahlu surga\". Maka kami bertakbir lagi. Kemudian Beliau bersabda lagi: \"Aku berharap kalian menjadi di antara setengah ahlu surga\". Maka kami bertakbir sekali lagi. Lalu Beliau bersabda: \"Tidaklah keberadan kalian di hadapan manusia melainkan bagaikan bulu hitam pada kulit sapi jantan putih atau bagaikan bulu putih yang ada pada kulit sapi jantan hitam\"."},{"p":"Muslim","n":320,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ الْعَبْسِيُّ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ يَا آدَمُ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ قَالَ يَقُولُ أَخْرِجْ بَعْثَ النَّارِ قَالَ وَمَا بَعْثُ النَّارِ قَالَ مِنْ كُل��ِ أَلْفٍ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ قَالَ فَذَاكَ حِينَ يَشِيبُ الصَّغِيرُ{ وَتَضَعُ كُلُّ ذَاتِ حَمْلٍ حَمْلَهَا وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى وَلَكِنَّ عَذَابَ اللَّهِ شَدِيدٌ }قَالَ فَاشْتَدَّ عَلَيْهِمْ قَالُوا يَا رَسُولَ اللَّهِ أَيُّنَا ذَلِكَ الرَّجُلُ فَقَالَ أَبْشِرُوا فَإِنَّ مِنْ يَأْجُوجَ وَمَأْجُوجَ أَلْفًا وَمِنْكُمْ رَجُلٌ قَالَ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا رُبُعَ أَهْلِ الْجَنَّةِ فَحَمِدْنَا اللَّهَ وَكَبَّرْنَا ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ فَحَمِدْنَا اللَّهَ وَكَبَّرْنَا ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا شَطْرَ أَهْلِ الْجَنَّةِ إِنَّ مَثَلَكُمْ فِي الْأُمَمِ كَمَثَلِ الشَّعْرَةِ الْبَيْضَاءِ فِي جِلْدِ الثَّوْرِ الْأَسْوَدِ أَوْ كَالرَّقْمَةِ فِي ذِرَاعِ الْحِمَارِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ كِلَاهُمَا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُمَا قَالَا مَا أَنْتُمْ يَوْمَئِذٍ فِي النَّاسِ إِلَّا كَالشَّعْرَةِ الْبَيْضَاءِ فِي الثَّوْرِ الْأَسْوَدِ أَوْ كَالشَّعْرَةِ السَّوْدَاءِ فِي الثَّوْرِ الْأَبْيَضِ وَلَمْ يَذْكُرَا أَوْ كَالرَّقْمَةِ فِي ذِرَاعِ الْحِمَارِ","trj":"Telah menceritakan kepada kami [Utsman bin Abu syaibah al-'Absyi] telah menceritakan kepada kami [Jarir] dari [al-A'masy] dari [Abu Shalih] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah berfirman, \"Wahai Adam! Lalu Adam menyahut, \"Aku penuhi panggilan-Mu dengan senang hati, dan kebaikan ada di tangan-Mu.\" Allah berfirman: \"Keluarkan orang yang dikirimkan ke Neraka.\" Adam bertanya, \"Berapa orang yang dikirim ke Neraka itu?\" Allah berfirman: \"Dari setiap seribu orang, dikeluarkan sembilan ratus sembilan puluh sembilan orang.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua itu terjadi ketika anak-anak beruban: '(Wanita yang hamil akan gugur kandungan dan manusia berada di dalam keadaan mabuk, sedangkan sebenarnya mereka tidak mabuk tetapi siksa Allah yang amat dahsyat) ' (Qs. Al Hajj: 2). Sabda Rasulullah shallallahu 'alaihi wasallam tersebut membingungkan para Sahabat. Maka mereka bertanya, \"Wahai Rasulullah. Siapakah lelaki itu di antara kami dari seribu orang ini?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bergembiralah kamu karena di antara seribu itu ialah Yakjuj dan Makjuj, sedangkan dari kamu hanya satu orang.\" Kemudian beliau bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sesungguhnya aku mengharapkan kamu menjadi seperempat dari penduduk Surga\". Maka kami (para Sahabat) memuji Allah dan bertakbir. Beliau bersabda lagi: \"Demi Dzat yang jiwaku berada di tangan-Nya, sesungguhnya aku mengharapkan kamu akan menjadi sepertiga dari penduduk Surga.\" Kami memuji Allah dan bertakbir. Kemudian beliau bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sesungguhnya aku mengharapkan kamu menjadi setengah dari penduduk Surga. Perumpamaan kamu di tengah-tengah umat lain, bagaikan sehelai bulu putih pada lembu hitam atau seperti tanda di betis Keledai.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki']. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Muawiyah] keduanya meriwayatkan dari [al-A'masy] dengan sanad ini, hanya saja keduanya menyebutkan, \"Tidaklah kalian berada pada manusia pada waktu itu meliankan seperti bula putih pada sapi hitam atau bulu hitam pada sapi putih.\" Dan keduanya tidak menyebutkan, \"Seperti tanda di betis keledai.\""},{"p":"Tirmidzi","n":2796,"ar":"حَدَّثَنَا أَبُو زُرْعَةَ وَالْفَضْلُ بْنُ أَبِي طَالِبٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا الْحَسَنُ بْنُ بِشْرٍ عَنْ الْحَكَمِ بْنِ عَبْدِ الْمَلِكِ عَنْ قَتَادَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَلَا نَعْرِفُ لِقَتَادَةَ سَمَاعًا مِنْ أَحَدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ أَنَسٍ وَأَبِي الطُّفَيْلِ وَهَذَا عِنْدِي مُخْتَصَرٌ إِنَّمَا يُرْوَى عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَرَأَ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ }الْحَدِيثَ بِطُولِهِ وَحَدِيثُ الْحَكَمِ بْنِ عَبْدِ الْمَلِكِ عِنْدِي مُخْتَصَرٌ مِنْ هَذَا الْحَدِيثِ","trj":"Telah menceritakan kepada kami [Abu Zur'ah] dan [Al Fadhal bin Abu Thalib] dan yang lainnya, mereka berkata; telah menceritakan kepada kami [Al Hasan bin Bisyr] dari [Al Hakam bin Abdul Malik] dari [Qatadah] dari ['Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam membaca: \"WATARAN NAASA SUKAARAA WA MAA HUM BI SUKAARAA (kamu lihat manusia dalam keadaan mabuk, padahal Sebenarnya mereka tidak mabuk).\" QS Al-Hajj: 2. Abu Isa berkata; Hadits ini hasan, kami tidak mengetahui Qatadah pernah mendengar dari salah seorang sahabat Nabi shallallahu 'alaihi wasallam kecuali dari Anas dan Abu Thufail, dan hadits ini menurut saya hanya ringkasan, hadits ini hanya diriwayatkan dari [Qatadah] dari [Al Hasan] dari [Imran bin Hushain], dia berkata; Kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, kemudian beliau membaca: \"YAA AYYUHAN NAASUT TAQUU RABBAKUM (Wahai sekalian manusia, takutlah kalian kepada Rabb kalian).\" QS Al Hajj: 1 dengan redaksi yang panjang, sementara hadits Al Hakam bin Abdul Malik menurutku ringkasan dari hadits ini."}],"22:19":[{"p":"Bukhari","n":3499,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي يَقُولُ حَدَّثَنَا أَبُو مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَأَنَا أَوَّلُ مَنْ يَجْثُو بَيْنَ يَدَيْ الرَّحْمَنِ لِلْخُصُومَةِ يَوْمَ الْقِيَامَةِ وَقَالَ قَيْسُ بْنُ عُبَادٍ وَفِيهِمْ أُنْزِلَتْ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }قَالَ هُمْ الَّذِينَ تَبَارَزُوا يَوْمَ بَدْرٍ حَمْزَةُ وَعَلِيٌّ وَعُبَيْدَةُ أَوْ أَبُو عُبَيْدَةَ بْنُ الْحَارِثِ وَشَيْبَةُ بْنُ رَبِيعَةَ وَعُتْبَةُ بْنُ رَبِيعَةَ وَالْوَلِيدُ بْنُ عُتْبَةَ","trj":"Telah menceritakan kepadaku [Muhammad bin Abdullah Ar-Raqasyiy] telah menceritakan kepada kami [Mu'tamir] berkata, aku mendengar [bapakku] berkata, telah menceritakan kepada kami [Abu Mijlaz] dari [Qais bin 'Ubad] dari ['Ali bin Abi Thalib] radliallahu 'anhu bahwa dia berkata; \"Aku adalah orang pertama yang akan berlutut di hadapan Allah Yang Maha Pengasih untuk berperkara pada hari qiyamat\". Dan Qais bin 'Ubad berkata; \"Telah turun ayat tentang mereka: \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\" (QS al-Hajj ayat 19). Mereka adalah orang yang berperang tanding pada perang Badar, yaitu Hamzah. 'Ali, 'Ubaidah atau Abu 'Ubaidah bin Al Harits menghadapi Syaibah bin Rabi'ah, 'Utbah bin Rabi'ah dan Al Walid bin 'Utbah\"."},{"p":"Bukhari","n":3500,"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَنَزَلَتْ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }فِي سِتَّةٍ مِنْ قُرَيْشٍ عَلِيٍّ وَحَمْزَةَ وَعُبَيْدَةَ بْنِ الْحَارِثِ وَشَيْبَةَ بْنِ رَبِيعَةَ وَعُتْبَةَ بْنِ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُتْبَةَ","trj":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin 'Ubad] dari [Abu Dzarr] radliallahu 'anhu berkata; \"QS al-Hajj ayat 19. yang artinya; \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\" turun tentang enam orang dari Quraisy, yaitu yaitu Ali, Hamzah, 'Ubaidah bin Al Harits, Syaibah bin Rabi'ah, 'Utbah bin Rabi'ah dan Al Walid bin 'Utbah\"."},{"p":"Bukhari","n":3501,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الصَّوَّافُ حَدَّثَنَا يُوسُفُ بْنُ يَعْقُوبَ كَانَ يَنْزِلُ فِي بَنِي ضُبَيْعَةَ وَهُوَ مَوْلًى لِبَنِي سَدُوسَ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُفِينَا نَزَلَتْ هَذِهِ الْآيَةُ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Ash Shawwaf] telah menceritakan kepada kami [Yusuf bin Ya'qub, dia pernah menetap tinggal di Bani Dlubai'ah, dia adalah maula Bani Sudus] telah menceritakan kepada kami [Sulaiman at-Taymiy] dari [Abu Mijlaz] dari [Qais bin 'Ubad] berkata, ['Ali] radliallahu 'anhu berkata; \"Ayat ini turun tentang kami, yaitu QS al-Hajj ayat 19. yang artinya; \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\"."},{"p":"Bukhari","n":3503,"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَ سَمِعْتُ أَبَا ذَرٍّيُقْسِمُ قَسَمًا إِنَّ هَذِهِ الْآيَةَ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }نَزَلَتْ فِي الَّذِينَ بَرَزُوا يَوْمَ بَدْرٍ حَمْزَةَ وَعَلِيٍّ وَعُبَيْدَةَ بْنِ الْحَارِثِ وَعُتْبَةَ وَشَيْبَةَ ابْنَيْ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُتْبَةَ","trj":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim ad-Dawraqiy] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin 'Ubad] berkata, aku mendengar [Abu Dzarr] bersumpah dengan suatu sumpah yang isinya bahwa sesungguhnya ayat ini: \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\" (QS al-Hajj ayat 19) diturunkan untuk mereka yang melakukan perang tanding pada perang Badar. Mereka adalah Hamzah, Ali, 'Ubaidah bin Al Harits, 'Utbah dan Syaibah, dua putra Rabi'ah dan Al Walid bin 'Utbah\"."}],"22:30":[{"p":"Abu Dawud","n":3046,"ar":"حَدَّثَنِي يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنِي سُفْيَانُ يَعْنِي الْعُصْفُرِيَّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ عَنْ خُرَيْمِ بْنِ فَاتِكٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عُدِلَتْ شَهَادَةُ الزُّورِ بِالْإِشْرَاكِ بِاللَّهِ ثَلَاثَ مِرَارٍ ثُمَّ قَرَأَ{ فَاجْتَنِبُوا الرِّجْسَ مِنْ الْأَوْثَانِ وَاجْتَنِبُوا قَوْلَ الزُّورِ حُنَفَاءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِ }","trj":"Telah menceritakan kepadaku [Yahya bin Musa Al Balkhi] telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepadaku [Sufyan Al 'Ushfuri] dari [Ayahnya] dari [Habib bin An Nu'man Al Asadi] dari [Khuraim bin Fatik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan Shalat Subuh, selesai shalat beliau bangkit dan berkata: \"Persaksian palsu disamakan dengan perbuatan mensekutukan Allah.\" Beliau mengucapkannya sebanyak tiga kali. Kemudian beliau membaca ayat: '(Maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta dengan ikhlas kepada Allah) ' (Qs. Al Hajj: 30). "},{"p":"Ahmad","n":1629,"ar":"حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ أَنْبَأَنَا سُفْيَانُ بْنُ زِيَادٍ عَنْ فَاتِكِ بْنِ فَضَالَةَ عَنْ أَيْمَنَ بْنِ خُرَيْمٍ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا فَقَالَ يَا أَيُّهَا النَّاسُ عَدَلَتْ شَهَادَةُ الزُّورِ إِشْرَاكًا بِاللَّهِ ثَلَاثًا ثُمَّ قَرَأَ{ فَاجْتَنِبُوا الرِّجْسَ مِنْ الْأَوْثَانِ وَاجْتَنِبُوا قَوْلَ الزُّورِ }","trj":"Telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] telah memberitakan kepada kami [Sufyan bin Ziyad] dari [Fatik bin Fadlalah] dari [Aiman bin Khuraim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri menyampaikan khutbah seraya bersabda: \"Wahai sekalian manusia, saksi palsu itu sama dengan syirik kepada Allah.\" Beliau mengucapkannya tiga kali, kemudian beliau membaca ayat: '(Maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta) ' (Qs. Al Hajj: 30)."},{"p":"Ibnu Majah","n":2328,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا سُفْيَانُ الْعُصْفُرِيُّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عُدِلَتْ شَهَادَةُ الزُّورِ بِالْإِشْرَاكِ بِاللَّهِ ثَلَاثَ مَرَّاتٍ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَاجْتَنِبُوا قَوْلَ الزُّورِ حُنَفَاءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِ }","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Sufyan Al 'Ushfuri] dari [Bapaknya] dari [Habib An Nu'mani Al Asadi] dari [Khuraim bin Fatik Al Asadi] ia berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat subuh, setelah selesai beliau berdiri dan bersabda: \"Persaksian palsu itu sama dengan syirik kepada Allah.\" Hal itu beliau ucapkan hingga tiga kali, setelah itu beliau membaca ayat: ' maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta. dengan ikhlas kepada Allah, tidak mempersekutukan sesuatu dengan Dia'. QS. Al Hajj: 30-31.\""}],"22:31":[{"p":"Ibnu Majah","n":2328,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا سُفْيَانُ الْعُصْفُرِيُّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عُدِلَتْ شَهَادَةُ الزُّورِ بِالْإِشْرَاكِ بِاللَّهِ ثَلَاثَ مَرَّاتٍ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَاجْتَنِبُوا قَوْلَ الزُّورِ حُنَفَاءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِ }","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Sufyan Al 'Ushfuri] dari [Bapaknya] dari [Habib An Nu'mani Al Asadi] dari [Khuraim bin Fatik Al Asadi] ia berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat subuh, setelah selesai beliau berdiri dan bersabda: \"Persaksian palsu itu sama dengan syirik kepada Allah.\" Hal itu beliau ucapkan hingga tiga kali, setelah itu beliau membaca ayat: ' maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta. dengan ikhlas kepada Allah, tidak mempersekutukan sesuatu dengan Dia'. QS. Al Hajj: 30-31.\""}],"22:33":[{"p":"Muslim","n":2041,"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ قَالَ كَانَ ابْنُ عَبَّاسٍ يَقُولُا لَا يَطُوفُ بِالْبَيْتِ حَاجٌّ وَلَا غَيْرُ حَاجٍّ إِلَّا حَلَّ قُلْتُ لِعَطَاءٍ مِنْ أَيْنَ يَقُولُ ذَلِكَ قَالَ مِنْ قَوْلِ اللَّهِ تَعَالَى{ ثُمَّ مَحِلُّهَا إِلَى الْبَيْتِ الْعَتِيقِ }قَالَ قُلْتُ فَإِنَّ ذَلِكَ بَعْدَ الْمُعَرَّفِ فَقَالَ كَانَ ابْنُ عَبَّاسٍ يَقُولُ هُوَ بَعْدَ الْمُعَرَّفِ وَقَبْلَهُوَكَانَ يَأْخُذُ ذَلِكَ مِنْ أَمْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَمَرَهُمْ أَنْ يَحِلُّوا فِي حَجَّةِ الْوَدَاعِ","trj":"Dan Telah meceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Atha`] ia berkata; \"Tidaklah seorang haji melakukan thawaf di Baitullah dan tidak pula seorang yang tidak haji kecuali ia telah tahallul.\" Saya bertanya kepada Atha`, \"Atas dasar apa yang berkata seperti itu?\" Ia menjawab, \"Dari firman Allah Ta'ala: \"Kemudian tempat wajib (serta akhir masa) menyembelihnya ialah setelah sampai ke Baitul Atiq (Baitullah).\" (QS. Alhajj 33). Aku berkata, \"Sesungguhnya hal itu adalah setelah wukuf di Arafah.\" Atha` berkata, \" [Ibnu Abbas] telah mengatakan bahwa hal itu adalah setelah dan sesudah wukuf di Arafah. Dan ia mengambil hal itu dari perkara Nabi shallallahu 'alaihi wasallam, saat beliau memerintahkan mereka untuk tahallul pada haji wada'.\""}],"22:47":[{"p":"Ibnu Majah","n":4075,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا أَبُو غَسَّانَ بَهْلُولٌ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَاشْتَكَى فُقَرَاءُ الْمُهَاجِرِينَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فَضَّلَ اللَّهُ بِهِ عَلَيْهِمْ أَغْنِيَاءَهُمْ فَقَالَ يَا مَعْشَرَ الْفُقَرَاءِ أَلَا أُبَشِّرُكُمْ أَنَّ فُقَرَاءَ الْمُؤْمِنِينَ يَدْخُلُونَ الْجَنَّةَ قَبْلَ أَغْنِيَائِهِمْ بِنِصْفِ يَوْمٍ خَمْسِ مِائَةِ عَامٍ ثُمَّ تَلَا مُوسَى هَذِهِ الْآيَةَ{ وَإِنَّ يَوْمًا عِنْدَ رَبِّكَ كَأَلْفِ سَنَةٍ مِمَّا تَعُدُّونَ }","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah memberitakan kepada kami [Abu Ghasan Bahlul] telah menceritakan kepada kami [Musa bin 'Ubaidah] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] dia berkata, \"Orang-orang fakir Muhajirin mengadu kepada Rasulullah shallallahu 'alaihi wasallam atas karunia Allah yang diberikan kepada orang-orang kaya, beliau bersabda: \"Wahai orang-orang miskin, maukah aku beri kabar gembira kepada kalian? Sesungguhnya orang-orang fakir miskin dari kaum Mukminin akan masuk surga sebelum orang-orang kaya dengan jarak setengah hari yang setara dengan lima ratus tahun.\" Kemudian Musa membaca ayat ini: '(Sesungguhnya sehari di sisi Tuhanmu adalah seperti seribu menurut perhitunganmu) ' (Qs. Al Hajj: 47)."}]},"mapping_surah":[{"p":"Abu Dawud","n":1164,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ بْنِ الْبَرْقِيِّ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا نَافِعُ بْنُ يَزِيدَ عَنْ الْحَارِثِ بْنِ سَعِيدٍ الْعُتَقِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مُنَيْنٍ مِنْ بَنِي عَبْدِ كُلَالٍ عَنْ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَهُ خَمْسَ عَشْرَةَ سَجْدَةً فِي الْقُرْآنِ مِنْهَا ثَلَاثٌ فِي الْمُفَصَّلِ وَفِي سُورَةِ الْحَجِّ سَجْدَتَانِقَالَ أَبُو دَاوُد رُوِيَ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى عَشْرَةَ سَجْدَةً وَإِسْنَادُهُ وَاهٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim bin Al Buraqi] telah menceritakan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Nafi' bin Yazid] dari [Al Harits bin Sa'id Al 'Utaqi] dari [Abdullah bin Munain] dari Bani Abdul Kulal, dari ['Amru bin Al 'Ash] bahwa Rasulullah shallallahu 'alaihi wasallam pernah membacakan untuknya lima belas ayat sajadah dalam Al Qur'an, di antaranya tiga ayat terdapat dalam surat Al Mufashal (dari surat Qaaf atau Al Hujurat sampai an naas), dan dalam surat Al Hajj dua ayat sajadah.\" Abu Daud berkata; \"di riwayatkan dari Abu Darda` dari Nabi shallallahu 'alaihi wasallam terdapat sebelas ayat sajadah, sedangkan sanadnya lemah.\""},{"p":"Abu Dawud","n":3046,"ar":"حَدَّثَنِي يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنِي سُفْيَانُ يَعْنِي الْعُصْفُرِيَّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ عَنْ خُرَيْمِ بْنِ فَاتِكٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عُدِلَتْ شَهَادَةُ الزُّورِ بِالْإِشْرَاكِ بِاللَّهِ ثَلَاثَ مِرَارٍ ثُمَّ قَرَأَ{ فَاجْتَنِبُوا الرِّجْسَ مِنْ الْأَوْثَانِ وَاجْتَنِبُوا قَوْلَ الزُّورِ حُنَفَاءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِ }","trj":"Telah menceritakan kepadaku [Yahya bin Musa Al Balkhi] telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepadaku [Sufyan Al 'Ushfuri] dari [Ayahnya] dari [Habib bin An Nu'man Al Asadi] dari [Khuraim bin Fatik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan Shalat Subuh, selesai shalat beliau bangkit dan berkata: \"Persaksian palsu disamakan dengan perbuatan mensekutukan Allah.\" Beliau mengucapkannya sebanyak tiga kali. Kemudian beliau membaca ayat: '(Maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta dengan ikhlas kepada Allah) ' (Qs. Al Hajj: 30). "},{"p":"Ahmad","n":1629,"ar":"حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ أَنْبَأَنَا سُفْيَانُ بْنُ زِيَادٍ عَنْ فَاتِكِ بْنِ فَضَالَةَ عَنْ أَيْمَنَ بْنِ خُرَيْمٍ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا فَقَالَ يَا أَيُّهَا النَّاسُ عَدَلَتْ شَهَادَةُ الزُّورِ إِشْرَاكًا بِاللَّهِ ثَلَاثًا ثُمَّ قَرَأَ{ فَاجْتَنِبُوا الرِّجْسَ مِنْ الْأَوْثَانِ وَاجْتَنِبُوا قَوْلَ الزُّورِ }","trj":"Telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] telah memberitakan kepada kami [Sufyan bin Ziyad] dari [Fatik bin Fadlalah] dari [Aiman bin Khuraim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri menyampaikan khutbah seraya bersabda: \"Wahai sekalian manusia, saksi palsu itu sama dengan syirik kepada Allah.\" Beliau mengucapkannya tiga kali, kemudian beliau membaca ayat: '(Maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta) ' (Qs. Al Hajj: 30)."},{"p":"Bukhari","n":3053,"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْأَعْمَشِ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ تَعَالَى يَا آدَمُ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ فَيَقُولُ أَخْرِجْ بَعْثَ النَّارِ قَالَ وَمَا بَعْثُ النَّارِ قَالَ مِنْ كُلِّ أَلْفٍ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ فَعِنْدَهُ يَشِيبُ الصَّغِيرُ{ وَتَضَعُ كُلُّ ذَاتِ حَمْلٍ حَمْلَهَا وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى وَلَكِنَّ عَذَابَ اللَّهِ شَدِيدٌ }قَالُوا يَا رَسُولَ اللَّهِ وَأَيُّنَا ذَلِكَ الْوَاحِدُ قَالَ أَبْشِرُوا فَإِنَّ مِنْكُمْ رَجُلًا وَمِنْ يَأْجُوجَ وَمَأْجُوجَ أَلْفًا ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي أَرْجُو أَنْ تَكُونُوا رُبُعَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَا فَقَالَ أَرْجُو أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَا فَقَالَ أَرْجُو أَنْ تَكُونُوا نِصْفَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَا فَقَالَ مَا أَنْتُمْ فِي النَّاسِ إِلَّا كَالشَّعَرَةِ السَّوْدَاءِ فِي جِلْدِ ثَوْرٍ أَبْيَضَ أَوْ كَشَعَرَةٍ بَيْضَاءَ فِي جِلْدِ ثَوْرٍ أَسْوَدَ","trj":"Telah bercerita kepadaku [Ishaq bin Nashr] telah bercerita kepada kami [Abu Usamah] dari [Al A'masy] telah bercerita kepada kami [Abu Shalih] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: \"Wahai Adam, \". Nabi Adam 'Alaihissalam menjawab: \"Labbaika, kemuliaan milik-Mu dan segala kebaikan berada di tangan-Mu\". Kemudian Allah berfirman: \"Keluarkanlah utusan neraka\". Adam bertanya; \"Apa yang dimaksud dengan utusan neraka? (berapa jumlahnya?) \". Allah berfirman: \"Dari setiap seribu, sembilan ratus sembilan puluh Sembilan dijebloskan neraka!, Ketika perintah ini diputuskan, maka anak-anak belia menjadi beruban, dan setiap wanita hamil kandungannya berguguran dan kamu lihat manusia mabuk padahal mereka tidaklah mabuk akan tetapi (mereka melihat) siksa Allah yang sangat keras\". (QS. Alhajj 2), Para shahabat bertanya; \"Wahai Rasulullah, adakah diantara kami seseorang yang selamat?\". Beliau bersabda: \"Bergembiralah, karena setiap seribu yang dimasukkan neraka, dari kalian cuma satu, sedang Sembilan ratus sembilan puluh sembilannya dari Ya'juj dan ma'juj\". Kemudian Beliau bersabda: \"Dan demi Dzat yang jiwaku berada di tangan-Nya, aku berharap kalian menjadi di antara seperempat ahlu surga\". Maka kami bertakbir. Kemudian Beliau bersabda lagi: \"Aku berharap kalian menjadi di antara sepertiga ahlu surga\". Maka kami bertakbir lagi. Kemudian Beliau bersabda lagi: \"Aku berharap kalian menjadi di antara setengah ahlu surga\". Maka kami bertakbir sekali lagi. Lalu Beliau bersabda: \"Tidaklah keberadan kalian di hadapan manusia melainkan bagaikan bulu hitam pada kulit sapi jantan putih atau bagaikan bulu putih yang ada pada kulit sapi jantan hitam\"."},{"p":"Bukhari","n":3499,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي يَقُولُ حَدَّثَنَا أَبُو مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَأَنَا أَوَّلُ مَنْ يَجْثُو بَيْنَ يَدَيْ الرَّحْمَنِ لِلْخُصُومَةِ يَوْمَ الْقِيَامَةِ وَقَالَ قَيْسُ بْنُ عُبَادٍ وَفِيهِمْ أُنْزِلَتْ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }قَالَ هُمْ الَّذِينَ تَبَارَزُوا يَوْمَ بَدْرٍ حَمْزَةُ وَعَلِيٌّ وَعُبَيْدَةُ أَوْ أَبُو عُبَيْدَةَ بْنُ الْحَارِثِ وَشَيْبَةُ بْنُ رَبِيعَةَ وَعُتْبَةُ بْنُ رَبِيعَةَ وَالْوَلِيدُ بْنُ عُتْبَةَ","trj":"Telah menceritakan kepadaku [Muhammad bin Abdullah Ar-Raqasyiy] telah menceritakan kepada kami [Mu'tamir] berkata, aku mendengar [bapakku] berkata, telah menceritakan kepada kami [Abu Mijlaz] dari [Qais bin 'Ubad] dari ['Ali bin Abi Thalib] radliallahu 'anhu bahwa dia berkata; \"Aku adalah orang pertama yang akan berlutut di hadapan Allah Yang Maha Pengasih untuk berperkara pada hari qiyamat\". Dan Qais bin 'Ubad berkata; \"Telah turun ayat tentang mereka: \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\" (QS al-Hajj ayat 19). Mereka adalah orang yang berperang tanding pada perang Badar, yaitu Hamzah. 'Ali, 'Ubaidah atau Abu 'Ubaidah bin Al Harits menghadapi Syaibah bin Rabi'ah, 'Utbah bin Rabi'ah dan Al Walid bin 'Utbah\"."},{"p":"Bukhari","n":3500,"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَنَزَلَتْ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }فِي سِتَّةٍ مِنْ قُرَيْشٍ عَلِيٍّ وَحَمْزَةَ وَعُبَيْدَةَ بْنِ الْحَارِثِ وَشَيْبَةَ بْنِ رَبِيعَةَ وَعُتْبَةَ بْنِ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُتْبَةَ","trj":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin 'Ubad] dari [Abu Dzarr] radliallahu 'anhu berkata; \"QS al-Hajj ayat 19. yang artinya; \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\" turun tentang enam orang dari Quraisy, yaitu yaitu Ali, Hamzah, 'Ubaidah bin Al Harits, Syaibah bin Rabi'ah, 'Utbah bin Rabi'ah dan Al Walid bin 'Utbah\"."},{"p":"Bukhari","n":3501,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الصَّوَّافُ حَدَّثَنَا يُوسُفُ بْنُ يَعْقُوبَ كَانَ يَنْزِلُ فِي بَنِي ضُبَيْعَةَ وَهُوَ مَوْلًى لِبَنِي سَدُوسَ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُفِينَا نَزَلَتْ هَذِهِ الْآيَةُ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Ash Shawwaf] telah menceritakan kepada kami [Yusuf bin Ya'qub, dia pernah menetap tinggal di Bani Dlubai'ah, dia adalah maula Bani Sudus] telah menceritakan kepada kami [Sulaiman at-Taymiy] dari [Abu Mijlaz] dari [Qais bin 'Ubad] berkata, ['Ali] radliallahu 'anhu berkata; \"Ayat ini turun tentang kami, yaitu QS al-Hajj ayat 19. yang artinya; \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\"."},{"p":"Bukhari","n":3503,"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَ سَمِعْتُ أَبَا ذَرٍّيُقْسِمُ قَسَمًا إِنَّ هَذِهِ الْآيَةَ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }نَزَلَتْ فِي الَّذِينَ بَرَزُوا يَوْمَ بَدْرٍ حَمْزَةَ وَعَلِيٍّ وَعُبَيْدَةَ بْنِ الْحَارِثِ وَعُتْبَةَ وَشَيْبَةَ ابْنَيْ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُتْبَةَ","trj":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim ad-Dawraqiy] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin 'Ubad] berkata, aku mendengar [Abu Dzarr] bersumpah dengan suatu sumpah yang isinya bahwa sesungguhnya ayat ini: \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\" (QS al-Hajj ayat 19) diturunkan untuk mereka yang melakukan perang tanding pada perang Badar. Mereka adalah Hamzah, Ali, 'Ubaidah bin Al Harits, 'Utbah dan Syaibah, dua putra Rabi'ah dan Al Walid bin 'Utbah\"."},{"p":"Bukhari","n":5744,"ar":"حَدَّثَنِي يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ يَا آدَمُ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ قَالَ يَقُولُ أَخْرِجْ بَعْثَ النَّارِ قَالَ وَمَا بَعْثُ النَّارِ قَالَ مِنْ كُلِّ أَلْفٍ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ فَذَاكَ حِينَ يَشِيبُ الصَّغِيرُ{ وَتَضَعُ كُلُّ ذَاتِ حَمْلٍ حَمْلَهَا وَتَرَى النَّاسَ سَكْرَى وَمَا هُمْ بِسَكْرَى وَلَكِنَّ عَذَابَ اللَّهِ شَدِيدٌ }فَاشْتَدَّ ذَلِكَ عَلَيْهِمْ فَقَالُوا يَا رَسُولَ اللَّهِ أَيُّنَا ذَلِكَ الرَّجُلُ قَالَ أَبْشِرُوا فَإِنَّ مِنْ يَأْجُوجَ وَمَأْجُوجَ أَلْفًا وَمِنْكُمْ رَجُلٌ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ قَالَ فَحَمِدْنَا اللَّهَ وَكَبَّرْنَا ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا شَطْرَ أَهْلِ الْجَنَّةِ إِنَّ مَثَلَكُمْ فِي الْأُمَمِ كَمَثَلِ الشَّعَرَةِ الْبَيْضَاءِ فِي جِلْدِ الثَّوْرِ الْأَسْوَدِ أَوْ الرَّقْمَةِ فِي ذِرَاعِ الْحِمَارِ","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah berfirman; 'hai Adam'. 'Baik dan aku penuhi panggilan-MU ya Allah, dan seluruh kebaikan di tangan-Mu, \" Jawab Adam. Allah melanjutkan; 'datangkan utusan-utusan neraka! ' Adam menjawab; 'berapa utusan neraka? ' Tanya Adam. Allah menjawab; 'Setiap seribu orang, datangkan sembilan ratus sembilan puluh sembilan orang.' Dan ketika itulah anak kecil menjadi beruban karenanya, sebagaimana ayat; 'Dan setiap orang yang hamil melahirkan bayinya, dan kau lihat manusia mabuk padahal sejatinya mereka tidak mabuk, hanya karena siksa Alalh sedemikian dahsyatnya' (QS. Alhajj, 2).\" Yang demikian menjadikan mereka gusar, sehingga para sahabat bertanya-tanya; 'Wahai Rasulullah, siapa diantara kami yang termasuk dijebloskan ke neraka itu! ' Nabi menjawab; \"Tenanglah kalian, sebab jika Ya'juj dan ma'juj dimasukkan neraka sebanyak seribu, dari kalian hanya satu.\" Selanjutnya beliau bersabda: \"Demi Dzat yang jiwaku berada di Tangan-Nya, sungguh aku berkeinginan sekiranya kalian menjadi sepertiga penghuni surga.\" Kata Abu Said; lantas kami pun memuji Allah dan bertakbir, kemudian Nabi bersabda: \"Demi dzat yang jiwaku berad di Tangan-Nya, sungguh aku berharap jika kalian menjadi separoh penghuni surga, dan permisalan kalian dibandingkan umat lainnya hanyalah bagaikan sehelai rambut putih di kulit sapi hitam atau bagaikan belang hitam di lengan keledai.\""},{"p":"Ibnu Majah","n":1014,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ عَنْ نَافِعِ بْنِ يَزِيدَ حَدَّثَنَا الْحَارِثُ بْنُ سَعِيدٍ الْعُتَقِيُّ عَنْ عَبْدِ اللَّهِ بْنِ مُنَيْنٍ مِنْ بَنِي عَبْدِ كِلَالٍ عَنْ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَهُ خَمْسَ عَشْرَةَ سَجْدَةً فِي الْقُرْآنِ مِنْهَا ثَلَاثٌ فِي الْمُفَصَّلِ وَفِي الْحَجِّ سَجْدَتَيْنِ","trj":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Abu Maryam] dari [Nafi' bin Yazid] berkata, telah menceritakan kepada kami [Al Harits bin Sa'id Al 'Utaqi] dari [Abdullah bin Munain] -seorang dari Bani Abdu Kilal- dari [Amru bin Al 'Ash] bahwasanya Rasulullah shallallahu 'alaihi wasallam membacakan kepadanya lima belas ayat sajadah dalam Al Qur'an; di antaranya tiga dalam Al Mufashshal dan dua dalam di Surat Al Hajj. \" "},{"p":"Ibnu Majah","n":2328,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا سُفْيَانُ الْعُصْفُرِيُّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عُدِلَتْ شَهَادَةُ الزُّورِ بِالْإِشْرَاكِ بِاللَّهِ ثَلَاثَ مَرَّاتٍ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَاجْتَنِبُوا قَوْلَ الزُّورِ حُنَفَاءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِ }","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Sufyan Al 'Ushfuri] dari [Bapaknya] dari [Habib An Nu'mani Al Asadi] dari [Khuraim bin Fatik Al Asadi] ia berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat subuh, setelah selesai beliau berdiri dan bersabda: \"Persaksian palsu itu sama dengan syirik kepada Allah.\" Hal itu beliau ucapkan hingga tiga kali, setelah itu beliau membaca ayat: ' maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta. dengan ikhlas kepada Allah, tidak mempersekutukan sesuatu dengan Dia'. QS. Al Hajj: 30-31.\""},{"p":"Ibnu Majah","n":4075,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا أَبُو غَسَّانَ بَهْلُولٌ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَاشْتَكَى فُقَرَاءُ الْمُهَاجِرِينَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فَضَّلَ اللَّهُ بِهِ عَلَيْهِمْ أَغْنِيَاءَهُمْ فَقَالَ يَا مَعْشَرَ الْفُقَرَاءِ أَلَا أُبَشِّرُكُمْ أَنَّ فُقَرَاءَ الْمُؤْمِنِينَ يَدْخُلُونَ الْجَنَّةَ قَبْلَ أَغْنِيَائِهِمْ بِنِصْفِ يَوْمٍ خَمْسِ مِائَةِ عَامٍ ثُمَّ تَلَا مُوسَى هَذِهِ الْآيَةَ{ وَإِنَّ يَوْمًا عِنْدَ رَبِّكَ كَأَلْفِ سَنَةٍ مِمَّا تَعُدُّونَ }","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah memberitakan kepada kami [Abu Ghasan Bahlul] telah menceritakan kepada kami [Musa bin 'Ubaidah] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] dia berkata, \"Orang-orang fakir Muhajirin mengadu kepada Rasulullah shallallahu 'alaihi wasallam atas karunia Allah yang diberikan kepada orang-orang kaya, beliau bersabda: \"Wahai orang-orang miskin, maukah aku beri kabar gembira kepada kalian? Sesungguhnya orang-orang fakir miskin dari kaum Mukminin akan masuk surga sebelum orang-orang kaya dengan jarak setengah hari yang setara dengan lima ratus tahun.\" Kemudian Musa membaca ayat ini: '(Sesungguhnya sehari di sisi Tuhanmu adalah seperti seribu menurut perhitunganmu) ' (Qs. Al Hajj: 47)."},{"p":"Malik","n":427,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ نَافِعٍ مَوْلَى ابْنِ عُمَرَ أَنَّ رَجُلًا مِنْ أَهْلِ مِصْرَ أَخْبَرَهُ أَنَّ عُمَرَ بْنَ الْخَطَّابِقَرَأَ سُورَةَ الْحَجِّ فَسَجَدَ فِيهَا سَجْدَتَيْنِ ثُمَّ قَالَ إِنَّ هَذِهِ السُّورَةَ فُضِّلَتْ بِسَجْدَتَيْنِ","trj":"Telah menceritakan kepadaku dari Malik dari [Nafi'] mantan budak Ibnu 'Umar, bahwa [seorang laki-laki] penduduk Mesir mengabarkan kepadanya, bahwa [Umar bin Khatthab] membaca Surat Al Hajj, lalu sujud karenanya dua kali. Lalu ia berkata, \"Surat ini diistimewakan dengan dua sujud.\""},{"p":"Malik","n":428,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ أَنَّهُ قَالَ رَأَيْتُ عَبْدَ اللَّهِ بْنَ عُمَرَيَسْجُدُ فِي سُورَةِ الْحَجِّ سَجْدَتَيْنِ","trj":"Telah menceritakan kepadaku dari Malik dari [Abdullah bin Dinar] bahwa dia berkata, \"Aku melihat [Abdullah bin Umar] sujud saat membaca Surat Al Hajj dengan dua kali sujud.\""},{"p":"Muslim","n":320,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ الْعَبْسِيُّ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ يَا آدَمُ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ قَالَ يَقُولُ أَخْرِجْ بَعْثَ النَّارِ قَالَ وَمَا بَعْثُ النَّارِ قَالَ مِنْ كُل��ِ أَلْفٍ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ قَالَ فَذَاكَ حِينَ يَشِيبُ الصَّغِيرُ{ وَتَضَعُ كُلُّ ذَاتِ حَمْلٍ حَمْلَهَا وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى وَلَكِنَّ عَذَابَ اللَّهِ شَدِيدٌ }قَالَ فَاشْتَدَّ عَلَيْهِمْ قَالُوا يَا رَسُولَ اللَّهِ أَيُّنَا ذَلِكَ الرَّجُلُ فَقَالَ أَبْشِرُوا فَإِنَّ مِنْ يَأْجُوجَ وَمَأْجُوجَ أَلْفًا وَمِنْكُمْ رَجُلٌ قَالَ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا رُبُعَ أَهْلِ الْجَنَّةِ فَحَمِدْنَا اللَّهَ وَكَبَّرْنَا ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ فَحَمِدْنَا اللَّهَ وَكَبَّرْنَا ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا شَطْرَ أَهْلِ الْجَنَّةِ إِنَّ مَثَلَكُمْ فِي الْأُمَمِ كَمَثَلِ الشَّعْرَةِ الْبَيْضَاءِ فِي جِلْدِ الثَّوْرِ الْأَسْوَدِ أَوْ كَالرَّقْمَةِ فِي ذِرَاعِ الْحِمَارِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ كِلَاهُمَا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُمَا قَالَا مَا أَنْتُمْ يَوْمَئِذٍ فِي النَّاسِ إِلَّا كَالشَّعْرَةِ الْبَيْضَاءِ فِي الثَّوْرِ الْأَسْوَدِ أَوْ كَالشَّعْرَةِ السَّوْدَاءِ فِي الثَّوْرِ الْأَبْيَضِ وَلَمْ يَذْكُرَا أَوْ كَالرَّقْمَةِ فِي ذِرَاعِ الْحِمَارِ","trj":"Telah menceritakan kepada kami [Utsman bin Abu syaibah al-'Absyi] telah menceritakan kepada kami [Jarir] dari [al-A'masy] dari [Abu Shalih] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah berfirman, \"Wahai Adam! Lalu Adam menyahut, \"Aku penuhi panggilan-Mu dengan senang hati, dan kebaikan ada di tangan-Mu.\" Allah berfirman: \"Keluarkan orang yang dikirimkan ke Neraka.\" Adam bertanya, \"Berapa orang yang dikirim ke Neraka itu?\" Allah berfirman: \"Dari setiap seribu orang, dikeluarkan sembilan ratus sembilan puluh sembilan orang.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua itu terjadi ketika anak-anak beruban: '(Wanita yang hamil akan gugur kandungan dan manusia berada di dalam keadaan mabuk, sedangkan sebenarnya mereka tidak mabuk tetapi siksa Allah yang amat dahsyat) ' (Qs. Al Hajj: 2). Sabda Rasulullah shallallahu 'alaihi wasallam tersebut membingungkan para Sahabat. Maka mereka bertanya, \"Wahai Rasulullah. Siapakah lelaki itu di antara kami dari seribu orang ini?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bergembiralah kamu karena di antara seribu itu ialah Yakjuj dan Makjuj, sedangkan dari kamu hanya satu orang.\" Kemudian beliau bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sesungguhnya aku mengharapkan kamu menjadi seperempat dari penduduk Surga\". Maka kami (para Sahabat) memuji Allah dan bertakbir. Beliau bersabda lagi: \"Demi Dzat yang jiwaku berada di tangan-Nya, sesungguhnya aku mengharapkan kamu akan menjadi sepertiga dari penduduk Surga.\" Kami memuji Allah dan bertakbir. Kemudian beliau bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sesungguhnya aku mengharapkan kamu menjadi setengah dari penduduk Surga. Perumpamaan kamu di tengah-tengah umat lain, bagaikan sehelai bulu putih pada lembu hitam atau seperti tanda di betis Keledai.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki']. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Muawiyah] keduanya meriwayatkan dari [al-A'masy] dengan sanad ini, hanya saja keduanya menyebutkan, \"Tidaklah kalian berada pada manusia pada waktu itu meliankan seperti bula putih pada sapi hitam atau bulu hitam pada sapi putih.\" Dan keduanya tidak menyebutkan, \"Seperti tanda di betis keledai.\""},{"p":"Muslim","n":2041,"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ قَالَ كَانَ ابْنُ عَبَّاسٍ يَقُولُا لَا يَطُوفُ بِالْبَيْتِ حَاجٌّ وَلَا غَيْرُ حَاجٍّ إِلَّا حَلَّ قُلْتُ لِعَطَاءٍ مِنْ أَيْنَ يَقُولُ ذَلِكَ قَالَ مِنْ قَوْلِ اللَّهِ تَعَالَى{ ثُمَّ مَحِلُّهَا إِلَى الْبَيْتِ الْعَتِيقِ }قَالَ قُلْتُ فَإِنَّ ذَلِكَ بَعْدَ الْمُعَرَّفِ فَقَالَ كَانَ ابْنُ عَبَّاسٍ يَقُولُ هُوَ بَعْدَ الْمُعَرَّفِ وَقَبْلَهُوَكَانَ يَأْخُذُ ذَلِكَ مِنْ أَمْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَمَرَهُمْ أَنْ يَحِلُّوا فِي حَجَّةِ الْوَدَاعِ","trj":"Dan Telah meceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Atha`] ia berkata; \"Tidaklah seorang haji melakukan thawaf di Baitullah dan tidak pula seorang yang tidak haji kecuali ia telah tahallul.\" Saya bertanya kepada Atha`, \"Atas dasar apa yang berkata seperti itu?\" Ia menjawab, \"Dari firman Allah Ta'ala: \"Kemudian tempat wajib (serta akhir masa) menyembelihnya ialah setelah sampai ke Baitul Atiq (Baitullah).\" (QS. Alhajj 33). Aku berkata, \"Sesungguhnya hal itu adalah setelah wukuf di Arafah.\" Atha` berkata, \" [Ibnu Abbas] telah mengatakan bahwa hal itu adalah setelah dan sesudah wukuf di Arafah. Dan ia mengambil hal itu dari perkara Nabi shallallahu 'alaihi wasallam, saat beliau memerintahkan mereka untuk tahallul pada haji wada'.\""},{"p":"Muslim","n":2217,"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ أَخْبَرَنِي ابْنُ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ قَالَ لَمَّا احْتَرَقَ الْبَيْتُ زَمَنَ يَزِيدَ بْنِ مُعَاوِيَةَ حِينَ غَزَاهَا أَهْلُ الشَّامِ فَكَانَ مِنْ أَمْرِهِ مَا كَانَ تَرَكَهُ ابْنُ الزُّبَيْرِ حَتَّى قَدِمَ النَّاسُ الْمَوْسِمَ يُرِيدُ أَنْ يُجَرِّئَهُمْ أَوْ يُحَرِّبَهُمْ عَلَى أَهْلِ الشَّامِ فَلَمَّا صَدَرَ النَّاسُ قَالَ يَا أَيُّهَا النَّاسُ أَشِيرُوا عَلَيَّ فِي الْكَعْبَةِ أَنْقُضُهَا ثُمَّ أَبْنِي بِنَاءَهَا أَوْ أُصْلِحُ مَا وَهَى مِنْهَا قَالَ ابْنُ عَبَّاسٍ فَإِنِّي قَدْ فُرِقَ لِي رَأْيٌ فِيهَا أَرَى أَنْ تُصْلِحَ مَا وَهَى مِنْهَا وَتَدَعَ بَيْتًا أَسْلَمَ النَّاسُ عَلَيْهِ وَأَحْجَارًا أَسْلَمَ النَّاسُ عَلَيْهَا وَبُعِثَ عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ابْنُ الزُّبَيْرِ لَوْ كَانَ أَحَدُكُمْ احْتَرَقَ بَيْتُهُ مَا رَضِيَ حَتَّى يُجِدَّهُ فَكَيْفَ بَيْتُ رَبِّكُمْ إِنِّي مُسْتَخِيرٌ رَبِّي ثَلَاثًا ثُمَّ عَازِمٌ عَلَى أَمْرِي فَلَمَّا مَضَى الثَّلَاثُ أَجْمَعَ رَأْيَهُ عَلَى أَنْ يَنْقُضَهَا فَتَحَامَاهُ النَّاسُ أَنْ يَنْزِلَ بِأَوَّلِ ال��َّاسِ يَصْعَدُ فِيهِ أَمْرٌ مِنْ السَّمَاءِ حَتَّى صَعِدَهُ رَجُلٌ فَأَلْقَى مِنْهُ حِجَارَةً فَلَمَّا لَمْ يَرَهُ النَّاسُ أَصَابَهُ شَيْءٌ تَتَابَعُوا فَنَقَضُوهُ حَتَّى بَلَغُوا بِهِ الْأَرْضَ فَجَعَلَ ابْنُ الزُّبَيْرِ أَعْمِدَةً فَسَتَّرَ عَلَيْهَا السُّتُورَ حَتَّى ارْتَفَعَ بِنَاؤُهُ وَقَالَ ابْنُ الزُّبَيْرِ إِنِّي سَمِعْتُ عَائِشَةَ تَقُولُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنَّ النَّاسَ حَدِيثٌ عَهْدُهُمْ بِكُفْرٍ وَلَيْسَ عِنْدِي مِنْ النَّفَقَةِ مَا يُقَوِّي عَلَى بِنَائِهِ لَكُنْتُ أَدْخَلْتُ فِيهِ مِنْ الْحِجْرِ خَمْسَ أَذْرُعٍ وَلَجَعَلْتُ لَهَا بَابًا يَدْخُلُ النَّاسُ مِنْهُ وَبَابًا يَخْرُجُونَ مِنْهُقَالَ فَأَنَا الْيَوْمَ أَجِدُ مَا أُنْفِقُ وَلَسْتُ أَخَافُ النَّاسَ قَالَ فَزَادَ فِيهِ خَمْسَ أَذْرُعٍ مِنْ الْحِجْرِ حَتَّى أَبْدَى أُسًّا نَظَرَ النَّاسُ إِلَيْهِ فَبَنَى عَلَيْهِ الْبِنَاءَ وَكَانَ طُولُ الْكَعْبَةِ ثَمَانِيَ عَشْرَةَ ذِرَاعًا فَلَمَّا زَادَ فِيهِ اسْتَقْصَرَهُ فَزَادَ فِي طُولِهِ عَشْرَ أَذْرُعٍ وَجَعَلَ لَهُ بَابَيْنِ أَحَدُهُمَا يُدْخَلُ مِنْهُ وَالْآخَرُ يُخْرَجُ مِنْهُ فَلَمَّا قُتِلَ ابْنُ الزُّبَيْرِ كَتَبَ الْحَجَّاجُ إِلَى عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ يُخْبِرُهُ بِذَلِكَ وَيُخْبِرُهُ أَنَّ ابْنَ الزُّبَيْرِ قَدْ وَضَعَ الْبِنَاءَ عَلَى أُسٍّ نَظَرَ إِلَيْهِ الْعُدُولُ مِنْ أَهْلِ مَكَّةَ فَكَتَبَ إِلَيْهِ عَبْدُ الْمَلِكِ إِنَّا لَسْنَا مِنْ تَلْطِيخِ ابْنِ الزُّبَيْرِ فِي شَيْءٍ أَمَّا مَا زَادَ فِي طُولِهِ فَأَقِرَّهُ وَأَمَّا مَا زَادَ فِيهِ مِنْ الْحِجْرِ فَرُدَّهُ إِلَى بِنَائِهِ وَسُدَّ الْبَابَ الَّذِي فَتَحَهُ فَنَقَضَهُ وَأَعَادَهُ إِلَى بِنَائِهِ","trj":"Telah menceritakan kepada kami [Hannad bin As Sariya] Telah menceritakan kepada kami [Ibnu Abu Zaidah] telah mengabarkan kepadaku [Ibnu Abu Sulaiman] dari [Atha`] ia berkata; Ketika Baitullah terbakar pada masa Yazid bin Mu'awiyah tatkala diperangi oleh penduduk Syam, dia perintahkan agar Baitullah dibiarkan apa adanya. [Ibnu Zubair] juga membiarkannya hingga orang-orang datang pada musim haji dengan maksud agar Ibnu Zubair bisa menggerakkan orang-orang itu untuk melawan penduduk Syam. Setelah orang-orang pergi ke Baitullah, Ibnu Zubair berkata, \"Saudara-saudara, berilah aku petunjuk (saran) tentang Ka'bah! Apakah aku harus membongkarnya lalu aku membangun kembali, akau aku perbaiki bagian-baigian yang rusak saja?\" Ibnu Abbas menjawab, \"Aku mempunyai pendapat tentang Ka'bah tersebut. Menurutku, sebaiknya Anda memperbaiki bagian-bagian yang rusak saja dan biarkanlah Baitullah dalam keadaan seperti ketika orang-orang dulu baru mulai memeluk Islam. Biarkan pula batu-batu seperti ketika orang-orang baru mulai memeluk Islam dan seperti ketika Nabi shallallahu 'alaihi wasallam diutus.\" Ibnu Zubair mengingatkan, \"Seandainya salah seorang diantara kalian rumahnya terbakar, tentu ia tidak akan rela sehingga dia membangunnya kembali dengan sebaik-baiknya, padahal ini adalah rumah Rabb kalian. sesungguhnya aku akan beristikharah untuk meminta petunjuk kepada Rabb-ku selama tiga kali, baru kemudian aku akan menetunkan keputusanku.\" Setelah tiga kali istikharah, maka Ibnu Zubair memastikan pendapatnya untuk membongkar Ka'bah. Orang-orang menghindari dari Baitullah, jangan-jangan ada bencana dari atas yang akan menimpa orang yang naik ke Baitullah kali pertama, sehingga ada seorang memanjat lalu menjatuhkan batunya. Setelah orang-orang melihat tidak ada sesuatu yang menimpa pemanjat tersebut, barulah orang-orang berduyun-duyun merobohkannya hingga rata dengan tanah. Kemudian Ibnu Zubair memancangkan beberapa tiang lalu memasang tabir sampai kemudian bangunan tersebut meninggi. Ibnu Zubair berkata; Aku pernah mendengar [Aisyah] berkata bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seandainya orang-orang tidak baru saja meninggalkan kekufuran dan seandainya aku mempunyai biaya yang cukup untuk membangun Baitullah sekarang ini, maka tentu aku sudah memasukkan hijr dan aku buat satu pintu masuk serta satu pintu keluar.\" Ibnu Zubair berkata, \"Sekarang aku sudah mempunyai biaya dan aku tidak khawatir terhadap keimanan kaum muslimin.\" Atha berkata; Lalu Ibnu Zubair menambah luas Baitullah sebanyak lima hasta di bagian Hijr, kemudian ia menjelaskan posisi pondasi dengan dilihat orang banyak., lalu diantas pondasi itu didirikan bangunan. Panjang Ka'bah semual dua belas hasta tetapi setelah diperluas maka panjangnya tampak pendek, sehingga panjangnya ditambah sepuluh hasta. Lalu dibuat dua pintu, satu pintu masuk, dan satu pintu keluar. Setelah Ibnu Zubair terbunuh, Al Hajjaj mengirim surat kepada Abdul Malik bin Marwan untuk memberitahukan hal itu kepadanya, juga untuk memberitahukan bahwa Ibnu Zubair telah membuat bangunan di pondasi yang telah dilihat oleh kebanyakan penduduk Makkah. Jadi Abdul Malik membalas surat Al Hajjaj; \"Kami sedikit pun tidak mengikuti kesalahan Ibnu Zubair. Tentang penambahan panjang Ka'bah oleh Ibnu Zubair, maka aku tetapkan, adapun penambahan luas Ka'bah di Hijr oleh Ibnu Zubair, maka kembalikanlah seperti keadaan sebelumnya dan tutuplah pintu yang dibuat oleh Ibnu Zubair.\" Lalu Ibnu Hajjaj pun membongkar Ka'bah dan mengembalikannya seperti keadaan semula."},{"p":"Tirmidzi","n":2796,"ar":"حَدَّثَنَا أَبُو زُرْعَةَ وَالْفَضْلُ بْنُ أَبِي طَالِبٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا الْحَسَنُ بْنُ بِشْرٍ عَنْ الْحَكَمِ بْنِ عَبْدِ الْمَلِكِ عَنْ قَتَادَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَلَا نَعْرِفُ لِقَتَادَةَ سَمَاعًا مِنْ أَحَدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ أَنَسٍ وَأَبِي الطُّفَيْلِ وَهَذَا عِنْدِي مُخْتَصَرٌ إِنَّمَا يُرْوَى عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَرَأَ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ }الْحَدِيثَ بِطُولِهِ وَحَدِيثُ الْحَكَمِ بْنِ عَبْدِ الْمَلِكِ عِنْدِي مُخْتَصَرٌ مِنْ هَذَا الْحَدِيثِ","trj":"Telah menceritakan kepada kami [Abu Zur'ah] dan [Al Fadhal bin Abu Thalib] dan yang lainnya, mereka berkata; telah menceritakan kepada kami [Al Hasan bin Bisyr] dari [Al Hakam bin Abdul Malik] dari [Qatadah] dari ['Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam membaca: \"WATARAN NAASA SUKAARAA WA MAA HUM BI SUKAARAA (kamu lihat manusia dalam keadaan mabuk, padahal Sebenarnya mereka tidak mabuk).\" QS Al-Hajj: 2. Abu Isa berkata; Hadits ini hasan, kami tidak mengetahui Qatadah pernah mendengar dari salah seorang sahabat Nabi shallallahu 'alaihi wasallam kecuali dari Anas dan Abu Thufail, dan hadits ini menurut saya hanya ringkasan, hadits ini hanya diriwayatkan dari [Qatadah] dari [Al Hasan] dari [Imran bin Hushain], dia berkata; Kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, kemudian beliau membaca: \"YAA AYYUHAN NAASUT TAQUU RABBAKUM (Wahai sekalian manusia, takutlah kalian kepada Rabb kalian).\" QS Al Hajj: 1 dengan redaksi yang panjang, sementara hadits Al Hakam bin Abdul Malik menurutku ringkasan dari hadits ini."}]};
